mapper.select:
SELECT COUNT(*)
FROM tb_auth_login_history
WHERE company_code_snapshot = #{companyCode}
  AND login_ip = #{loginIp}
  AND login_result != 'SUCCESS'
  AND created_at >= #{since}

mapper.update:
UPDATE tb_member
SET login_failed_count = login_failed_count + 1,
    locked_until_at = #{lockedUntilAt}
WHERE company_id = #{companyId}
  AND member_id = #{memberId}

UPDATE tb_member
SET last_login_at = CURRENT_TIMESTAMP(6),
    login_failed_count = 0,
    locked_until_at = NULL,
    last_login_ip = #{lastLoginIp},
    last_login_user_agent = #{lastLoginUserAgent}
WHERE company_id = #{companyId}
  AND member_id = #{memberId}

UPDATE tb_auth_refresh_token
SET revoked_at = CURRENT_TIMESTAMP(6),
    revoked_reason = #{revokedReason},
    replaced_by_token_id = #{replacedByTokenId}
WHERE token_id = #{tokenId}
  AND revoked_at IS NULL

UPDATE tb_auth_refresh_token
SET revoked_at = CURRENT_TIMESTAMP(6),
    revoked_reason = #{revokedReason}
WHERE company_id = #{companyId}
  AND member_id = #{memberId}
  AND token_family_id = #{tokenFamilyId}
  AND revoked_at IS NULL

UPDATE tb_auth_refresh_token
SET revoked_at = CURRENT_TIMESTAMP(6),
    revoked_reason = #{revokedReason}
WHERE company_id = #{companyId}
  AND member_id = #{memberId}
  AND revoked_at IS NULL
